const int g_cn_font_count = 7000;

const uint8_t* find_cn_bitmap(const char *utf8_char) {
    for (int i = 0; i < g_cn_font_count; i++) {
        if (strncmp(g_cn_map[i].utf8, utf8_char, 3) == 0) {
            return g_cn_map[i].data;
        }
    }
    return NULL;
}

// 获取Unicode编码
uint16_t find_cn_unicode(const char *utf8_char) {
    for (int i = 0; i < g_cn_font_count; i++) {
        if (strncmp(g_cn_map[i].utf8, utf8_char, 3) == 0) {
            return g_cn_map[i].unicode;
        }
    }
    return 0;  // 未找到返回0
}

// 同时获取字模和Unicode
typedef struct {
    const uint8_t *data;
    uint16_t unicode;
} CN_Char_Info;

CN_Char_Info find_cn_info(const char *utf8_char) {
    CN_Char_Info info = {NULL, 0};
    
    for (int i = 0; i < g_cn_font_count; i++) {
        if (strncmp(g_cn_map[i].utf8, utf8_char, 3) == 0) {
            info.data = g_cn_map[i].data;
            info.unicode = g_cn_map[i].unicode;
            return info;
        }
    }
    
    return info;
}

// 二分查找版本（前提：g_cn_map按UTF-8排序）
const uint8_t* find_cn_bitmap_fast(const char *utf8_char) {
    int left = 0, right = g_cn_font_count - 1;
    
    while (left <= right) {
        int mid = (left + right) / 2;
        int cmp = strncmp(g_cn_map[mid].utf8, utf8_char, 3);
        
        if (cmp == 0) {
            return g_cn_map[mid].data;
        } else if (cmp < 0) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    
    return NULL;
}